sql:
SELECT MAX(satisfaction_threshold) 
FROM satisfaction_levels 
WHERE satisfaction_level_name = '2' AND level_description LIKE '%Employee has low satisfaction with their job%';

SELECT COUNT(job_role_id) 
FROM job_roles 
WHERE required_experience_years = 2;

SELECT AVG(score_threshold) AS average_threshold
FROM behaviour_scores
WHERE description IN ('Poor behavior', 'Very poor behavior') AND score_threshold <= 2;

SELECT COUNT(department_id) AS departments_count
FROM departments
WHERE headcount > (SELECT AVG(headcount) FROM departments);

external_knowledge:
- 'Path of solitude' refers to travel options with a `travel_frequency` of 'Never';
- 'Budget that doesn't fall into the void' means `travel_budget` > 0;
- 'Stand in the grand scheme of all travel budgets' refers to the cumulative distribution of travel budgets.

sql:
SELECT COUNT(*) AS active_education_fields
FROM education_fields
WHERE field_status = 'Active';

SELECT AVG(budget) AS average_budget
FROM departments
WHERE budget > (SELECT AVG(budget) FROM departments);

SELECT department_name
FROM departments
WHERE headcount > 100 AND budget > 4000000;

external_knowledge:
- 'Wilted flowers' refers to employees who have left the company;
- 'Struggled to communicate' refers to employees with very poor communication skills;
- 'Barely met the performance criteria' refers to employees with a low performance rating;
- 'Plucked from the company's soil' refers to employees who have left the company.

- 'shining stars' refers to departments with the highest average last performance ratings;
- 'standing tall among their peers' means ranking in the top 5;
- 'former employees' are those who have left the company and are recorded in the attrition table.

sql:
SELECT AVG(involvement_threshold) AS avg_job_involvement_threshold
FROM job_involvement_levels
WHERE job_involvement_level_name = '2';

SELECT AVG(average_salary) AS average_salary
FROM education_fields
WHERE education_field_name = 'Life Sciences' AND average_salary > 50000;

SELECT description 
FROM stock_option_levels 
WHERE option_threshold = (SELECT MAX(option_threshold) FROM stock_option_levels);

SELECT COUNT(job_involvement_level_id) 
FROM job_involvement_levels 
WHERE involvement_threshold > 1;

SELECT job_involvement_level_name
FROM job_involvement_levels
WHERE job_involvement_level_id = 2;

external_knowledge:
- "low involvement" refers to the lowest level on the job involvement scale (1-4), which is level 1;
- "moderate behavior" refers to the middle level on the behavior score scale (1-5), which is level 2;
- "moderate satisfaction" refers to the middle level on the satisfaction level scale (1-5), which is level 2;
- " Manufacturing Director" is a specific job role within the organization.

sql:
SELECT COUNT(DISTINCT job_role_id)
FROM job_roles
WHERE required_experience_years > 5 AND job_role_status = 'Active';

SELECT AVG(average_salary) AS average_salary
FROM education_fields
WHERE field_status = 'Active' AND education_field_name = 'Medical';

SELECT termination_type, COUNT(attrition_id) AS Attrition_Count
FROM attrition
GROUP BY termination_type;

external_knowledge:
- "Top 2 departments" refers to the departments with the highest budgets;
- "Department head" is the person in charge of the department, identified by `department_head_id`;
- "Fertile branches of a tree" is a metaphor for the most well-funded and potentially successful departments.

sql:
SELECT department_name, established_date
FROM departments
ORDER BY established_date DESC;

SELECT employee_id, last_salary, last_benefits
FROM attrition
WHERE termination_type = 'Involuntary';

external_knowledge:
- "Lower performance ratings (1, 2, or 3)" refer to the performance rating scale where 1 is the lowest and 4 is the highest;
- "Top 3 highest earners" means the employees with the highest salaries within their performance rating group;
- "Voluntary" termination type indicates that the employee chose to leave the company on their own accord;
- "Exit interview conducted" means that a formal discussion with the employee was held before they left, often to gather feedback on their experience and reasons for leaving.
